PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" (
  id   INTEGER PRIMARY KEY,
  name TEXT    NOT NULL,
  up   TEXT    NOT NULL,
  down TEXT    NOT NULL
);
INSERT INTO migrations VALUES(1,'initial',replace('PRAGMA foreign_keys = ON;\n\nCREATE TABLE category (\n  id    TEXT NOT NULL PRIMARY KEY,\n  name  TEXT NOT NULL,\n  slug  TEXT NOT NULL\n);\n\nCREATE TABLE post (\n  id         TEXT NOT NULL PRIMARY KEY,\n  categoryId TEXT NOT NULL,\n  name       TEXT NOT NULL,\n  slug       TEXT NOT NULL DEFAULT '''',\n  createdAt  TEXT NOT NULL DEFAULT (datetime(''now'')),\n  updatedAt  TEXT NOT NULL DEFAULT (datetime(''now'')),\n  status     TEXT NOT NULL DEFAULT ''draft'' CHECK (status IN (''published'', ''draft'')),\n\n  CONSTRAINT post_fk_categoryId FOREIGN KEY (categoryId)\n    REFERENCES category (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\n\nCREATE TABLE block (\n  id      TEXT NOT NULL PRIMARY KEY,\n  postId  TEXT,\n  blockId TEXT,\n  type    TEXT NOT NULL,\n  content TEXT NOT NULL,\n\n  CONSTRAINT block_fk_postId  FOREIGN KEY (postId)  REFERENCES post  (id) ON UPDATE CASCADE ON DELETE CASCADE,\n  CONSTRAINT block_fk_blockId FOREIGN KEY (blockId) REFERENCES block (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\n\nCREATE TABLE authtoken (\n  id    INTEGER PRIMARY KEY,\n  token TEXT    NOT NULL\n);\n\nCREATE INDEX post_ix_categoryId ON post  (categoryId);\nCREATE INDEX block_ix_postId    ON block (postId);','\n',char(10)),replace('DROP INDEX block_ix_postId;\nDROP INDEX post_ix_categoryId;\n\nDROP TABLE authtoken;\nDROP TABLE block;\nDROP TABLE post;\nDROP TABLE category;','\n',char(10)));
INSERT INTO migrations VALUES(2,'localizations',replace('CREATE TABLE localizations (\n  id      TEXT NOT NULL PRIMARY KEY,\n  key     TEXT NOT NULL,\n  locale  TEXT NOT NULL,\n  text    TEXT NOT NULL\n);\n\nCREATE UNIQUE INDEX localizations_ix_key_locale ON localizations (key, locale);\nCREATE INDEX         localizations_ix_key        ON localizations (key);\n\nCREATE TRIGGER trg_category_delete AFTER DELETE ON category BEGIN\n  DELETE FROM localizations WHERE key LIKE ''category:'' || old.id || '':%'';\nEND;\n\nCREATE TRIGGER trg_post_delete AFTER DELETE ON post BEGIN\n  DELETE FROM localizations WHERE key LIKE ''post:'' || old.id || '':%'';\nEND;\n\nCREATE TRIGGER trg_block_delete AFTER DELETE ON block BEGIN\n  DELETE FROM localizations WHERE key LIKE ''block:'' || old.id || '':%'';\nEND;','\n',char(10)),replace('DROP TRIGGER trg_block_delete;\nDROP TRIGGER trg_post_delete;\nDROP TRIGGER trg_category_delete;\nDROP INDEX localizations_ix_key;\nDROP INDEX localizations_ix_key_locale;\nDROP TABLE localizations;','\n',char(10)));
INSERT INTO migrations VALUES(3,'assets',replace('CREATE TABLE IF NOT EXISTS asset (\n  id        TEXT    PRIMARY KEY,\n  filename  TEXT    NOT NULL,\n  mime      TEXT    NOT NULL,\n  data      BLOB    NOT NULL,\n  createdAt INTEGER NOT NULL DEFAULT (unixepoch())\n);\n\nCREATE TABLE block_asset (\n  blockId TEXT NOT NULL,\n  assetId TEXT NOT NULL,\n\n  PRIMARY KEY (blockId, assetId),\n\n  CONSTRAINT block_asset_fk_blockId FOREIGN KEY (blockId)\n    REFERENCES block (id) ON DELETE CASCADE,\n  CONSTRAINT block_asset_fk_assetId FOREIGN KEY (assetId)\n    REFERENCES asset (id) ON DELETE CASCADE\n);\n\n\nCREATE TRIGGER trg_block_asset_delete AFTER DELETE ON block_asset BEGIN\n  DELETE FROM asset\n    WHERE id = old.assetId\n      AND NOT EXISTS (SELECT 1 FROM block_asset WHERE assetId = old.assetId);\nEND;','\n',char(10)),replace('DROP TRIGGER trg_block_asset_delete;\nDROP TABLE block_asset;\nDROP TABLE asset;','\n',char(10)));
INSERT INTO migrations VALUES(5,'fix_asset_cascade','DROP TRIGGER trg_block_asset_delete;',replace('CREATE TRIGGER trg_block_asset_delete AFTER DELETE ON block_asset BEGIN\n  DELETE FROM asset\n    WHERE id = old.assetId\n      AND NOT EXISTS (SELECT 1 FROM block_asset WHERE assetId = old.assetId);\nEND;','\n',char(10)));
INSERT INTO migrations VALUES(6,'shortid',replace('ALTER TABLE category ADD COLUMN shortid TEXT NOT NULL DEFAULT '''';\nUPDATE category SET shortid = substr(id, length(id) - 7);\nCREATE UNIQUE INDEX category_ix_shortid ON category (shortid);\n\nALTER TABLE post ADD COLUMN shortid TEXT NOT NULL DEFAULT '''';\nUPDATE post SET shortid = substr(id, length(id) - 7);\nCREATE UNIQUE INDEX post_ix_shortid ON post (shortid);','\n',char(10)),replace('DROP INDEX post_ix_shortid;\nALTER TABLE post DROP COLUMN shortid;\n\nDROP INDEX category_ix_shortid;\nALTER TABLE category DROP COLUMN shortid;','\n',char(10)));
INSERT INTO migrations VALUES(7,'pages_category','INSERT INTO category (id, shortid, name, slug) VALUES (''1E982CC4-47AB-4ADB-AB1F-24182319AB77'', ''2319AB77'', ''Pages'', ''pages'');','DELETE FROM category WHERE id = ''1E982CC4-47AB-4ADB-AB1F-24182319AB77'';');
INSERT INTO migrations VALUES(8,'parent_tables',replace('CREATE TABLE parent_block (\n  blockId     TEXT NOT NULL PRIMARY KEY,\n  parentId    TEXT NOT NULL,\n  parentTable TEXT NOT NULL,\n\n  CONSTRAINT parent_block_fk_blockId FOREIGN KEY (blockId)\n    REFERENCES block (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\nCREATE INDEX parent_block_ix_parent ON parent_block (parentTable, parentId);\n\nCREATE TABLE parent_post (\n  postId      TEXT NOT NULL PRIMARY KEY,\n  parentId    TEXT NOT NULL,\n  parentTable TEXT NOT NULL,\n\n  CONSTRAINT parent_post_fk_postId FOREIGN KEY (postId)\n    REFERENCES post (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\nCREATE INDEX parent_post_ix_parent ON parent_post (parentTable, parentId);\n\nINSERT INTO parent_block (blockId, parentId, parentTable)\nSELECT id, postId, ''post''\n  FROM block WHERE postId IS NOT NULL;\n\nINSERT INTO parent_block (blockId, parentId, parentTable)\nSELECT id, blockId, ''block''\n  FROM block WHERE blockId IS NOT NULL;\n\nINSERT INTO parent_post (postId, parentId, parentTable)\nSELECT id, categoryId, ''category''\n  FROM post;\n\n\n\n\n\nDROP INDEX block_ix_postId;\nDROP INDEX post_ix_categoryId;\n\nCREATE TABLE block_new (\n  id      TEXT NOT NULL PRIMARY KEY,\n  type    TEXT NOT NULL,\n  content TEXT NOT NULL\n);\nINSERT INTO block_new (id, type, content)\n  SELECT id, type, content FROM block;\nDROP TABLE block;\nALTER TABLE block_new RENAME TO block;\n\nCREATE TABLE post_new (\n  id        TEXT NOT NULL PRIMARY KEY,\n  shortid   TEXT NOT NULL DEFAULT '''',\n  name      TEXT NOT NULL,\n  slug      TEXT NOT NULL DEFAULT '''',\n  createdAt TEXT NOT NULL DEFAULT (datetime(''now'')),\n  updatedAt TEXT NOT NULL DEFAULT (datetime(''now'')),\n  status    TEXT NOT NULL DEFAULT ''draft'' CHECK (status IN (''published'', ''draft''))\n);\nINSERT INTO post_new (id, shortid, name, slug, createdAt, updatedAt, status)\n  SELECT id, shortid, name, slug, createdAt, updatedAt, status FROM post;\nDROP TABLE post;\nALTER TABLE post_new RENAME TO post;\n\nCREATE UNIQUE INDEX post_ix_shortid ON post (shortid);\n\n\nCREATE TRIGGER trg_post_delete AFTER DELETE ON post BEGIN\n  DELETE FROM localizations WHERE key LIKE ''post:'' || old.id || '':%'';\nEND;\n\nCREATE TRIGGER trg_block_delete AFTER DELETE ON block BEGIN\n  DELETE FROM localizations WHERE key LIKE ''block:'' || old.id || '':%'';\nEND;\n\n\nCREATE TRIGGER trg_post_delete_children_blocks AFTER DELETE ON post BEGIN\n  DELETE FROM block WHERE id IN (\n    SELECT blockId FROM parent_block\n     WHERE parentTable = ''post'' AND parentId = old.id\n  );\nEND;\n\nCREATE TRIGGER trg_block_delete_children_blocks AFTER DELETE ON block BEGIN\n  DELETE FROM block WHERE id IN (\n    SELECT blockId FROM parent_block\n     WHERE parentTable = ''block'' AND parentId = old.id\n  );\nEND;\n\nCREATE TRIGGER trg_category_delete_children_posts AFTER DELETE ON category BEGIN\n  DELETE FROM post WHERE id IN (\n    SELECT postId FROM parent_post\n     WHERE parentTable = ''category'' AND parentId = old.id\n  );\nEND;','\n',char(10)),replace('-- Also requires foreign_keys = OFF for the same reason.\n\nDROP TRIGGER trg_category_delete_children_posts;\nDROP TRIGGER trg_block_delete_children_blocks;\nDROP TRIGGER trg_post_delete_children_blocks;\nDROP TRIGGER trg_block_delete;\nDROP TRIGGER trg_post_delete;\n\nCREATE TABLE block_old (\n  id      TEXT NOT NULL PRIMARY KEY,\n  postId  TEXT,\n  blockId TEXT,\n  type    TEXT NOT NULL,\n  content TEXT NOT NULL,\n\n  CONSTRAINT block_fk_postId  FOREIGN KEY (postId)  REFERENCES post  (id) ON UPDATE CASCADE ON DELETE CASCADE,\n  CONSTRAINT block_fk_blockId FOREIGN KEY (blockId) REFERENCES block_old (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\nINSERT INTO block_old (id, postId, blockId, type, content)\n  SELECT b.id,\n         (SELECT parentId FROM parent_block WHERE blockId = b.id AND parentTable = ''post''),\n         (SELECT parentId FROM parent_block WHERE blockId = b.id AND parentTable = ''block''),\n         b.type, b.content\n    FROM block b;\nDROP TABLE block;\nALTER TABLE block_old RENAME TO block;\n\nCREATE TABLE post_old (\n  id         TEXT NOT NULL PRIMARY KEY,\n  categoryId TEXT NOT NULL,\n  shortid    TEXT NOT NULL DEFAULT '''',\n  name       TEXT NOT NULL,\n  slug       TEXT NOT NULL DEFAULT '''',\n  createdAt  TEXT NOT NULL DEFAULT (datetime(''now'')),\n  updatedAt  TEXT NOT NULL DEFAULT (datetime(''now'')),\n  status     TEXT NOT NULL DEFAULT ''draft'' CHECK (status IN (''published'', ''draft'')),\n\n  CONSTRAINT post_fk_categoryId FOREIGN KEY (categoryId)\n    REFERENCES category (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\nINSERT INTO post_old (id, categoryId, shortid, name, slug, createdAt, updatedAt, status)\n  SELECT p.id,\n         (SELECT parentId FROM parent_post WHERE postId = p.id AND parentTable = ''category''),\n         p.shortid, p.name, p.slug, p.createdAt, p.updatedAt, p.status\n    FROM post p;\nDROP TABLE post;\nALTER TABLE post_old RENAME TO post;\n\nCREATE INDEX post_ix_categoryId ON post  (categoryId);\nCREATE INDEX block_ix_postId    ON block (postId);\nCREATE UNIQUE INDEX post_ix_shortid ON post (shortid);\n\nCREATE TRIGGER trg_post_delete AFTER DELETE ON post BEGIN\n  DELETE FROM localizations WHERE key LIKE ''post:'' || old.id || '':%'';\nEND;\n\nCREATE TRIGGER trg_block_delete AFTER DELETE ON block BEGIN\n  DELETE FROM localizations WHERE key LIKE ''block:'' || old.id || '':%'';\nEND;\n\nDROP INDEX parent_post_ix_parent;\nDROP INDEX parent_block_ix_parent;\nDROP TABLE parent_post;\nDROP TABLE parent_block;','\n',char(10)));
INSERT INTO migrations VALUES(9,'pages',replace('CREATE TABLE page (\n  id  TEXT NOT NULL PRIMARY KEY,\n  key TEXT NOT NULL UNIQUE\n);\n\n\nCREATE TRIGGER trg_page_delete_children_blocks AFTER DELETE ON page BEGIN\n  DELETE FROM block WHERE id IN (\n    SELECT blockId FROM parent_block\n     WHERE parentTable = ''page'' AND parentId = old.id\n  );\nEND;\n\n\nCREATE TRIGGER trg_page_delete AFTER DELETE ON page BEGIN\n  DELETE FROM localizations WHERE key LIKE ''page:'' || old.id || '':%'';\nEND;','\n',char(10)),replace('DROP TRIGGER trg_page_delete;\nDROP TRIGGER trg_page_delete_children_blocks;\nDROP TABLE page;','\n',char(10)));
INSERT INTO migrations VALUES(10,'drop_pages_category','DELETE FROM category WHERE id = ''1E982CC4-47AB-4ADB-AB1F-24182319AB77'';','INSERT INTO category (id, shortid, name, slug) VALUES (''1E982CC4-47AB-4ADB-AB1F-24182319AB77'', ''2319AB77'', ''Pages'', ''pages'');');
INSERT INTO migrations VALUES(11,'users_and_tokens',replace('CREATE TABLE user (\n  id            TEXT NOT NULL PRIMARY KEY,\n  name          TEXT NOT NULL UNIQUE,\n  password_hash TEXT NOT NULL\n);\n\nDROP TABLE authtoken;\n\nCREATE TABLE authtoken (\n  id        INTEGER PRIMARY KEY,\n  token     TEXT NOT NULL UNIQUE,\n  userId    TEXT NOT NULL,\n  expiresAt TEXT NOT NULL,\n\n  CONSTRAINT authtoken_fk_userId FOREIGN KEY (userId)\n    REFERENCES user (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\n\nCREATE INDEX authtoken_ix_token  ON authtoken (token);\nCREATE INDEX authtoken_ix_userId ON authtoken (userId);','\n',char(10)),replace('DROP INDEX authtoken_ix_userId;\nDROP INDEX authtoken_ix_token;\nDROP TABLE authtoken;\nDROP TABLE user;\n\nCREATE TABLE authtoken (\n  id    INTEGER PRIMARY KEY,\n  token TEXT    NOT NULL\n);','\n',char(10)));
INSERT INTO migrations VALUES(12,'parent_asset',replace('CREATE TABLE parent_asset (\n  assetId     TEXT NOT NULL,\n  parentId    TEXT NOT NULL,\n  parentTable TEXT NOT NULL,\n\n  PRIMARY KEY (assetId, parentId, parentTable),\n\n  CONSTRAINT parent_asset_fk_assetId FOREIGN KEY (assetId)\n    REFERENCES asset (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\nCREATE INDEX parent_asset_ix_parent ON parent_asset (parentTable, parentId);\n\n\nCREATE TRIGGER trg_block_delete_parent_asset AFTER DELETE ON block BEGIN\n  DELETE FROM parent_asset\n    WHERE parentTable = ''block'' AND parentId = old.id;\nEND;\n\nINSERT INTO parent_asset (assetId, parentId, parentTable)\nSELECT assetId, blockId, ''block''\n  FROM block_asset;\n\nDROP TABLE block_asset;','\n',char(10)),replace('-- Also requires foreign_keys = OFF for the same reason.\n\nCREATE TABLE block_asset (\n  blockId TEXT NOT NULL,\n  assetId TEXT NOT NULL,\n\n  PRIMARY KEY (blockId, assetId),\n\n  CONSTRAINT block_asset_fk_blockId FOREIGN KEY (blockId)\n    REFERENCES block (id) ON DELETE CASCADE,\n  CONSTRAINT block_asset_fk_assetId FOREIGN KEY (assetId)\n    REFERENCES asset (id) ON DELETE CASCADE\n);\n\nINSERT INTO block_asset (blockId, assetId)\nSELECT parentId, assetId\n  FROM parent_asset WHERE parentTable = ''block'';\n\nDROP TRIGGER trg_block_delete_parent_asset;\nDROP INDEX parent_asset_ix_parent;\nDROP TABLE parent_asset;','\n',char(10)));
INSERT INTO migrations VALUES(13,'asset_content',replace('ALTER TABLE asset ADD COLUMN content TEXT;\n\nUPDATE asset\n   SET content = ''{"resolution":"@1x"}''\n WHERE mime LIKE ''image/%'';','\n',char(10)),'ALTER TABLE asset DROP COLUMN content;');
INSERT INTO migrations VALUES(14,'asset_output_as',replace('UPDATE asset\n   SET content = json_set(COALESCE(content, ''{}''), ''$.output_as'', json(''{"type":"original"}''))\n WHERE mime LIKE ''image/%'';','\n',char(10)),replace('UPDATE asset\n   SET content = json_remove(content, ''$.output_as'')\n WHERE mime LIKE ''image/%'';','\n',char(10)));
INSERT INTO migrations VALUES(15,'tags',replace('CREATE TABLE tag (\n  id        TEXT NOT NULL PRIMARY KEY,\n  shortid   TEXT NOT NULL DEFAULT '''',\n  name      TEXT NOT NULL,\n  slug      TEXT NOT NULL DEFAULT '''',\n  createdAt TEXT NOT NULL DEFAULT (datetime(''now'')),\n  updatedAt TEXT NOT NULL DEFAULT (datetime(''now''))\n);\nCREATE UNIQUE INDEX tag_ix_shortid ON tag (shortid);\n\nCREATE TABLE parent_tag (\n  tagId       TEXT NOT NULL,\n  parentId    TEXT NOT NULL,\n  parentTable TEXT NOT NULL,\n\n  PRIMARY KEY (tagId, parentId, parentTable),\n  CONSTRAINT parent_tag_fk_tagId FOREIGN KEY (tagId)\n    REFERENCES tag (id) ON UPDATE CASCADE ON DELETE CASCADE\n);\nCREATE INDEX parent_tag_ix_parent ON parent_tag (parentTable, parentId);\n\nCREATE TRIGGER trg_tag_delete AFTER DELETE ON tag BEGIN\n  DELETE FROM localizations WHERE key LIKE ''tag:'' || old.id || '':%'';\nEND;\n\n\nCREATE TRIGGER trg_post_delete_parent_tags AFTER DELETE ON post BEGIN\n  DELETE FROM parent_tag WHERE parentTable = ''post'' AND parentId = old.id;\nEND;','\n',char(10)),replace('DROP TRIGGER trg_post_delete_parent_tags;\nDROP TRIGGER trg_tag_delete;\nDROP INDEX parent_tag_ix_parent;\nDROP TABLE parent_tag;\nDROP INDEX tag_ix_shortid;\nDROP TABLE tag;','\n',char(10)));
INSERT INTO migrations VALUES(16,'parent_post_position',replace('ALTER TABLE parent_post ADD COLUMN position REAL NOT NULL DEFAULT 0;\n\nUPDATE parent_post AS pp\n   SET position = (\n     SELECT rn FROM (\n       SELECT postId,\n              ROW_NUMBER() OVER (PARTITION BY parentTable, parentId ORDER BY postId DESC) AS rn\n         FROM parent_post\n     ) s\n     WHERE s.postId = pp.postId\n   );\n\nCREATE INDEX parent_post_ix_parent_position\n  ON parent_post (parentTable, parentId, position);','\n',char(10)),replace('DROP INDEX parent_post_ix_parent_position;\nALTER TABLE parent_post DROP COLUMN position;','\n',char(10)));
CREATE TABLE category (
  id    TEXT NOT NULL PRIMARY KEY,
  name  TEXT NOT NULL,
  slug  TEXT NOT NULL
, shortid TEXT NOT NULL DEFAULT '');
