CREATE TABLE localizations (
  id      TEXT NOT NULL PRIMARY KEY,
  key     TEXT NOT NULL,
  locale  TEXT NOT NULL,
  text    TEXT NOT NULL
);
INSERT INTO localizations VALUES('019dbcf7-a559-752c-b8e4-e4b88f774e9d','block:019dbced-3ca1-72bd-a910-4cc8d2d77a5c:text','ru','Небольшая подключаемая CMS на базе Next.js 16 + SQLite. Поставляется в виде пакета, который устанавливается в приложение-потребитель на Next.js; потребитель отвечает за публичную маршрутизацию и контент, а CMS предоставляет админ-интерфейс, сервисы, доставку ассетов, миграции и CLI.');
