CREATE TABLE IF NOT EXISTS "block" (
  id      TEXT NOT NULL PRIMARY KEY,
  type    TEXT NOT NULL,
  content TEXT NOT NULL
);
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1e-fa15143cbe07','text','{"type":"text","key":"","text":"Birds are a diverse group of warm-blooded animals known for their feathers, wings, and ability to lay eggs. They live in almost every part of the world, from dense forests and open oceans to busy cities. One of their most defining features is their feathers, which help them fly, stay warm, and attract mates."}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1e-ff5433af9a3f','group','{"type":"group","key":""}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1f-02ac619911d4','image','{"type":"image","key":"","name":"01.avif","alt":"","assetId":"019dbcea-7409-72fb-854c-7b0215f7bf6f"}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1f-06fdd7133513','image','{"type":"image","key":"","name":"photo-1480044965905-02098d419e96.jpg","alt":"","assetId":"019dbcea-7558-727c-958c-f02ef7f51f68"}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1f-0a6bf3aa3707','image','{"type":"image","key":"","name":"photo-1484704324500-528d0ae4dc7d.jpg","alt":"","assetId":"019dbcea-765a-740c-b550-b460dc7e6a44"}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1f-0e16ae646c0b','image','{"type":"image","key":"","name":"photo-1591608971362-f08b2a75731a.jpg","alt":"","assetId":"019dbcea-7743-7222-bc79-14d8a26cb25e"}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1f-10ac7e80c392','image','{"type":"image","key":"","name":"photo-1636246441747-7d7f83f4629c.jpg","alt":"","assetId":"019dbcea-7867-732c-b2a5-5cee9ca90ba1"}');
INSERT INTO block VALUES('019dbceb-71c8-736f-8e1f-152beed81478','text','{"type":"text","key":"","text":"Most birds can fly, using powerful chest muscles and lightweight bones, although some species, like ostriches and penguins, have adapted to life without flight. Birds have excellent vision and many use songs and calls to communicate with each other. These sounds can warn of danger, attract partners, or mark territory."}');
INSERT INTO block VALUES('019dbced-3ca1-72bd-a910-4cc8d2d77a5c','text','{"type":"text","key":"description","text":"A small, pluggable CMS built on Next.js 16 + SQLite. Ships as a package you install into a Next.js consumer app; the consumer owns public routing and content, the CMS provides admin UI, services, asset delivery, migrations, and a CLI."}');
INSERT INTO block VALUES('019dbcfc-ada8-7509-ac15-e5d77e3cf61c','text','{"type":"text","key":"","text":"Cats communicate in various ways, including meowing, purring, hissing, and body language. A cat’s tail position, ear movement, and posture can all signal its mood. For example, a gently swaying tail may indicate curiosity, while flattened ears can be a sign of fear or aggression."}');
INSERT INTO block VALUES('019dbcfb-836c-766b-8401-fd5a3e82d226','group','{"type":"group","key":""}');
INSERT INTO block VALUES('019dbcfb-a465-74fb-bdef-510f65c837e3','image','{"type":"image","key":"","name":"photo-1548546738-8509cb246ed3.jpg","alt":"","assetId":"019dbcfc-cf75-77db-ac8f-acb3c56ba0cc"}');
INSERT INTO block VALUES('019dbcfb-b1fe-76fa-b2c9-87a2ab0d4ef2','image','{"type":"image","key":"","name":"photo-1472491235688-bdc81a63246e.jpg","alt":"","assetId":"019dbcfc-d0b9-73d9-8e89-5420a565710f"}');
INSERT INTO block VALUES('019dbcfb-c39f-744e-9174-64c5b984077b','image','{"type":"image","key":"","name":"photo-1571566882372-1598d88abd90.jpg","alt":"","assetId":"019dbcfc-d211-776e-964d-c2bdef1c03ad"}');
INSERT INTO block VALUES('019dbcfb-d0e4-717b-a9fc-712f1cd88094','image','{"type":"image","key":"","name":"photo-1574158622682-e40e69881006.jpg","alt":"","assetId":"019dbcfc-d408-72f2-a846-bc830b4547f5"}');
INSERT INTO block VALUES('019dbcfb-dd77-7639-ad00-df6c650cc064','image','{"type":"image","key":"","name":"photo-1596854407944-bf87f6fdd49e.jpg","alt":"","assetId":"019dbcfc-d521-705b-a119-437209663156"}');
INSERT INTO block VALUES('019dbcfc-8edd-7009-811d-a6fab65e45e4','text','{"type":"text","key":"","text":"Although many cats enjoy human attention, they are also known for their independence. They often spend time grooming themselves, which helps keep their fur clean and regulates body temperature. Despite their independent nature, cats can form strong bonds with their owners and show affection in subtle ways, such as purring, rubbing against people, or sitting nearby."}');
