CREATE TABLE tag (
  id        TEXT NOT NULL PRIMARY KEY,
  shortid   TEXT NOT NULL DEFAULT '',
  name      TEXT NOT NULL,
  slug      TEXT NOT NULL DEFAULT '',
  createdAt TEXT NOT NULL DEFAULT (datetime('now')),
  updatedAt TEXT NOT NULL DEFAULT (datetime('now'))
);
CREATE TABLE parent_tag (
  tagId       TEXT NOT NULL,
  parentId    TEXT NOT NULL,
  parentTable TEXT NOT NULL,

  PRIMARY KEY (tagId, parentId, parentTable),
  CONSTRAINT parent_tag_fk_tagId FOREIGN KEY (tagId)
    REFERENCES tag (id) ON UPDATE CASCADE ON DELETE CASCADE
);
CREATE TRIGGER trg_category_delete AFTER DELETE ON category BEGIN
  DELETE FROM localizations WHERE key LIKE 'category:' || old.id || ':%';
END;
CREATE TRIGGER trg_post_delete AFTER DELETE ON post BEGIN
  DELETE FROM localizations WHERE key LIKE 'post:' || old.id || ':%';
END;
CREATE TRIGGER trg_block_delete AFTER DELETE ON block BEGIN
  DELETE FROM localizations WHERE key LIKE 'block:' || old.id || ':%';
END;
CREATE TRIGGER trg_post_delete_children_blocks AFTER DELETE ON post BEGIN
  DELETE FROM block WHERE id IN (
    SELECT blockId FROM parent_block
     WHERE parentTable = 'post' AND parentId = old.id
  );
END;
CREATE TRIGGER trg_block_delete_children_blocks AFTER DELETE ON block BEGIN
  DELETE FROM block WHERE id IN (
    SELECT blockId FROM parent_block
     WHERE parentTable = 'block' AND parentId = old.id
  );
END;
CREATE TRIGGER trg_category_delete_children_posts AFTER DELETE ON category BEGIN
  DELETE FROM post WHERE id IN (
    SELECT postId FROM parent_post
     WHERE parentTable = 'category' AND parentId = old.id
  );
END;
CREATE TRIGGER trg_page_delete_children_blocks AFTER DELETE ON page BEGIN
  DELETE FROM block WHERE id IN (
    SELECT blockId FROM parent_block
     WHERE parentTable = 'page' AND parentId = old.id
  );
END;
CREATE TRIGGER trg_page_delete AFTER DELETE ON page BEGIN
  DELETE FROM localizations WHERE key LIKE 'page:' || old.id || ':%';
END;
CREATE TRIGGER trg_block_delete_parent_asset AFTER DELETE ON block BEGIN
  DELETE FROM parent_asset
    WHERE parentTable = 'block' AND parentId = old.id;
END;
CREATE TRIGGER trg_tag_delete AFTER DELETE ON tag BEGIN
  DELETE FROM localizations WHERE key LIKE 'tag:' || old.id || ':%';
END;
CREATE TRIGGER trg_post_delete_parent_tags AFTER DELETE ON post BEGIN
  DELETE FROM parent_tag WHERE parentTable = 'post' AND parentId = old.id;
END;
CREATE UNIQUE INDEX localizations_ix_key_locale ON localizations (key, locale);
CREATE INDEX localizations_ix_key        ON localizations (key);
CREATE UNIQUE INDEX category_ix_shortid ON category (shortid);
CREATE INDEX parent_block_ix_parent ON parent_block (parentTable, parentId);
CREATE INDEX parent_post_ix_parent ON parent_post (parentTable, parentId);
CREATE UNIQUE INDEX post_ix_shortid ON post (shortid);
CREATE INDEX authtoken_ix_token  ON authtoken (token);
CREATE INDEX authtoken_ix_userId ON authtoken (userId);
CREATE INDEX parent_asset_ix_parent ON parent_asset (parentTable, parentId);
CREATE UNIQUE INDEX tag_ix_shortid ON tag (shortid);
CREATE INDEX parent_tag_ix_parent ON parent_tag (parentTable, parentId);
CREATE INDEX parent_post_ix_parent_position
  ON parent_post (parentTable, parentId, position);
COMMIT;
